#!/usr/bin/env python3

# generator - generated by Gemini

import sys
import random
import string

# prevent recursion limit issues for deep formula generation
sys.setrecursionlimit(5000)

class WffGenerator:
    def __init__(self, var_count: int):
        self.var_count = max(1, min(var_count, 26))
        self.variables = string.ascii_lowercase[:self.var_count]
        self.binary_ops = ['&', '|', '>', '-']
        self.sub_wff_pool = [] 

    def generate(self, length: int, reuse_rate: float = 0.0) -> str:
        self.sub_wff_pool = []
        # length must be odd to allow for a well-formed formula structure
        if length < 1: length = 1
        if length > 1 and length % 2 == 0: length -= 1 
        return self._build(length, reuse_rate)

    def _build(self, n: int, reuse_rate: float) -> str:
        # reuse old sub-formula with certain probability, but only if n is large enough and pool has enough candidates
        if n > 3 and len(self.sub_wff_pool) > 5 and random.random() < reuse_rate:
            candidate = random.choice(self.sub_wff_pool)
            return candidate

        if n <= 1:
            res = random.choice(self.variables)
        elif n == 2: # impossible
            res = f"!{random.choice(self.variables)}"
        elif random.random() < 0.15: # 0.15 for a negation node
            res = f"!{self._build(n - 1, reuse_rate)}"
        else: # binary operator node
            op = random.choice(self.binary_ops)
            # for left and right sub-formulas, we need to ensure they can fit into n-1 characters (accounting for the operator)
            k = random.randrange(1, n - 1)
            if k % 2 == 0: k += 1
            if k >= n - 1: k = n - 2
            
            left = self._build(k, reuse_rate)
            right = self._build(n - 1 - k, reuse_rate)
            res = f"({left}{op}{right})"
        
        # add sub formula
        if len(res) < 50:
            self.sub_wff_pool.append(res)
        return res

def main():
    if len(sys.argv) < 3:
        print("Usage: python3 generator.py <length> <vars> [reuse_rate]")
        sys.exit(1)

    try:
        length = int(sys.argv[1])
        vars_count = int(sys.argv[2])
        reuse_rate = float(sys.argv[3]) if len(sys.argv) > 3 else 0.0
    except ValueError:
        sys.exit(1)

    gen = WffGenerator(vars_count)
    print(gen.generate(length, reuse_rate))

if __name__ == "__main__":
    main()